public class ShaderExample {
  public static void main(String[] args) throws Exception {
    Shader shader = Shader.loadShader("shader"); // Load a shader program from a file named "shader.vert" and "shader.frag".
    System.out.println("Program: " + shader.getProgram()); // Print the handle of the loaded shader program.
  }
}

public static void main(String[] args) {
        // Create a Matrix4f object and fill it with data.
        Matrix4f mat = new Matrix4f();
        mat.set(0, 0, 1);
        mat.set(1, 1, 2);
        mat.set(2, 2, 3);
        mat.set(3, 3, 4);
        // Create a Shader object and bind it to the current context.
        Shader shader = new Shader("myShader");
        shader.bind();
        // Call unifromMat4 with the name of the uniform variable in the shader program, and the Matrix4f object.
        shader.uniformMat4("myUniform", mat);
}

